// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('checked box', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('checked box', async function() {
    await driver.get("http://localhost:4200/admin-user/add-user");
    await driver.manage().window().setRect({ width: 1920, height: 1040 });
    await driver.findElement(By.css(".ant-btn-primary:nth-child(3) > span")).click();
    await driver.sleep(10000);
    vars["buttonAdd"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[1].disabled");
    assert(vars["buttonAdd"].toString() == "true");
    await driver.findElement(By.css(".ant-table-selection .ant-checkbox-input")).click();
    vars["checkedAll"] = await driver.executeScript("return document.getElementsByClassName(\"ant-checkbox-input\")[0].checked");
    assert(vars["checkedAll"].toString() == "true");
    vars["buttonAdd"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[1].disabled");
    assert(vars["buttonAdd"].toString() == "false");
    await driver.findElement(By.css(".ant-table-selection .ant-checkbox-input")).click();
    await driver.findElement(By.xpath("//div[@id=\'root\']/section/section/main/div/div/div/div/div/div/div/table/tbody/tr[2]/td/label/span/input")).click();
    vars["buttonAdd"] = await driver.executeScript("return document.getElementsByClassName(\"ant-btn css-dev-only-do-not-override-1km3mtt ant-btn-primary main_button\")[1].disabled");
    assert(vars["buttonAdd"].toString() == "false");
    vars["checkedAll"] = await driver.executeScript("return document.getElementsByClassName(\"ant-checkbox-input\")[0].checked");
    assert(vars["checkedAll"].toString() == "false");
  });
});
